 94→  w: PacketWriter,
 95→  opts: {
 96→    messageId: number;
 97→    messageType?: number;
 98→    senderGuid?: bigint;
 99→    senderEntry?: number;
100→    subject: string;
101→    body: string;
102→    flags?: number;
103→    expirationTime?: number;
104→    money?: number;
105→    itemCount?: number;
106→  },
107→): void {
108→  const msgType = opts.messageType ?? MailMessageType.NORMAL;
109→  const inner = new PacketWriter();
110→  inner.uint32LE(opts.messageId);
111→  inner.uint8(msgType);
112→  if (msgType === MailMessageType.NORMAL) {
113→    inner.uint64LE(opts.senderGuid ?? 0n);
114→  } else {
115→    inner.uint32LE(opts.senderEntry ?? 0);
116→  }
117→  inner.uint32LE(0);
