123→  inner.uint32LE(0);
124→  inner.cString(opts.subject);
125→  inner.cString(opts.body);
126→  inner.uint8(opts.itemCount ?? 0);
127→  const entryBytes = inner.finish();
128→  w.uint16LE(entryBytes.byteLength);
129→  w.rawBytes(entryBytes);
130→}
