    expect(parsed.type).toBe("MAIL_LIST");
    expect(parsed.count).toBe(2);
    expect(parsed.mails[0].messageId).toBe(5);
    expect(parsed.mails[0].read).toBe(false);
    expect(parsed.mails[0].money).toBe(100);
