254→function drainPackets(
255→  socket: Socket<ConnState>,
256→  authStatus: number,
257→  sendTimeSync: boolean,
258→  captured: CapturedPacket[],
259→  captureListeners: CaptureListener[],
260→  guildId = 0,
261→): void {
262→  while (true) {
263→    if (!socket.data.pendingHeader) {
264→      if (socket.data.buf.byteLength < 6) break;
265→      const headerBytes = socket.data.buf.slice(0, 6);
266→      socket.data.buf = socket.data.buf.slice(6);
267→      socket.data.pendingHeader = decryptClientHeader(
268→        headerBytes,
269→        socket.data.arc4,
270→      );
271→    }
272→
273→    const { size, opcode } = socket.data.pendingHeader;
274→    const bodySize = size - 4;
275→    if (socket.data.buf.byteLength < bodySize) break;
276→
277→    const body =
278→      bodySize > 0 ? socket.data.buf.slice(0, bodySize) : new Uint8Array(0);
279→    socket.data.buf = socket.data.buf.slice(bodySize);
280→    socket.data.pendingHeader = undefined;
281→
282→    handlePacket(
283→      socket,
284→      opcode,
285→      body,
286→      authStatus,
287→      sendTimeSync,
288→      captured,
289→      captureListeners,
290→      guildId,
291→    );
292→  }
293→}
