      const winner = new PacketWriter();
      winner.uint8(0);
      winner.cString("Loser");
      winner.cString("Winner");
      ws.inject(GameOpcode.SMSG_DUEL_WINNER, winner.finish());

      const events = await received;
      expect(events.map((e) => e.type)).toEqual([
        "duel_requested",
        "duel_countdown",
        "duel_out_of_bounds",
        "duel_in_bounds",
