      mailCache: [],
    } as unknown as WorldConn;
    handleSendMailResult(conn, new PacketReader(w.finish()));
    expect(msg!.message).toBe("Internal mail error.");
  });

  test("other action is ignored", () => {
    const w = new PacketWriter();
    w.uint32LE(1);
    w.uint32LE(2);
    w.uint32LE(0);
    let called = false;
    const conn = {
      onMessage: () => {
        called = true;
      },
      mailCache: [],
    } as unknown as WorldConn;
    handleSendMailResult(conn, new PacketReader(w.finish()));
    expect(called).toBe(false);
  });
});

