      {
        type: "duel_winner",
        reason: "won",
        winner: "A",
        loser: "B",
      },
      events,
      log,
    );
    const json = JSON.parse(events.drain()[0]!.json);
    expect(json).toEqual({
      type: "DUEL_WINNER",
      reason: "won",
      winner: "A",
      loser: "B",
    });
  });
});

