        expect(event.roster.guildName).toBe("Horde Elite");
        expect(event.roster.rankNames[0]).toBe("Guild Master");
        expect(event.roster.rankNames[1]).toBe("Officer");

        handle.close();
        await handle.closed;
      } finally {
        ws.stop();
      }
    });

